/**
 * dsp-defaults.js — Load generated DSP parameter defaults.
 *
 * Exports getDspDefault(kind) which returns the default params object
 * for a DSP block kind (e.g. 'flt', 'peq', 'cmp'), or null if unknown.
 * Defaults are sourced from web/src/generated/dsp-defaults.json which
 * is generated by: cargo run -p patchbox-core --bin gen-dsp-defaults
 */

let _defaults = null;

async function _load() {
  if (_defaults) return _defaults;
  try {
    const resp = await fetch('/generated/dsp-defaults.json');
    _defaults = await resp.json();
  } catch (e) {
    console.warn('dsp-defaults: failed to load', e);
    _defaults = {};
  }
  return _defaults;
}

/**
 * Returns a shallow clone of the default params for the given DSP block kind,
 * or null if the kind is unknown or defaults haven't loaded yet.
 * @param {string} kind - DSP block kind (e.g. 'flt', 'peq', 'cmp')
 * @returns {object|null}
 */
export function getDspDefault(kind) {
  if (!_defaults) return null;
  const d = _defaults[kind];
  return d ? { ...d } : null;
}

/**
 * Pre-loads defaults eagerly. Call once at app init so getDspDefault()
 * has data before any panels open.
 * @returns {Promise<void>}
 */
export async function loadDspDefaults() {
  await _load();
}
